 7→func TestCheckEnvGate(t *testing.T) {
 8→	tests := []struct {
 9→		name    string
10→		env     string
11→		wantErr bool
12→	}{
13→		{name: "development allowed", env: "development", wantErr: false},
14→		{name: "production blocked", env: "production", wantErr: true},
15→		{name: "staging blocked", env: "staging", wantErr: true},
16→		{name: "empty blocked", env: "", wantErr: true},
17→		{name: "random string blocked", env: "dev", wantErr: true},
18→	}
19→
20→	for _, tt := range tests {
21→		t.Run(tt.name, func(t *testing.T) {
22→			err := checkEnvGate(tt.env)
23→			if (err != nil) != tt.wantErr {
24→				t.Errorf("checkEnvGate(%q) error = %v, wantErr %v", tt.env, err, tt.wantErr)
25→			}
26→		})
27→	}
28→}
