 8→
 9→func TestHashPassword(t *testing.T) {
10→	hash, err := HashPassword("my-secret-password")
11→	if err != nil {
12→		t.Fatalf("HashPassword() error = %v", err)
13→	}
14→	if hash == "" {
15→		t.Fatal("HashPassword() returned empty string")
16→	}
17→	// Verify it's valid bcrypt
18→	if err := bcrypt.CompareHashAndPassword([]byte(hash), []byte("my-secret-password")); err != nil {
19→		t.Errorf("produced hash is not valid bcrypt: %v", err)
20→	}
21→}
22→
23→func TestHashPassword_DifferentHashes(t *testing.T) {
24→	h1, _ := HashPassword("password")
25→	h2, _ := HashPassword("password")
26→	if h1 == h2 {
27→		t.Error("same password should produce different hashes (different salts)")
28→	}
29→}
30→
31→func TestCheckPassword_Correct(t *testing.T) {
32→	hash, _ := HashPassword("correct-password")
33→	if err := CheckPassword(hash, "correct-password"); err != nil {
34→		t.Errorf("CheckPassword() with correct password: %v", err)
35→	}
36→}
37→
38→func TestCheckPassword_Wrong(t *testing.T) {
39→	hash, _ := HashPassword("correct-password")
40→	if err := CheckPassword(hash, "wrong-password"); err == nil {
41→		t.Error("CheckPassword() with wrong password should return error")
42→	}
43→}
44→
45→func TestCheckPassword_InvalidHash(t *testing.T) {
46→	if err := CheckPassword("not-a-bcrypt-hash", "password"); err == nil {
47→		t.Error("CheckPassword() with invalid hash should return error")
48→	}
