 8→func TestIntegrationTestDB(t *testing.T) {
 9→	if testing.Short() {
10→		t.Skip("skipping: requires Docker")
11→	}
12→
13→	pool := TestDB(t)
14→	ctx := context.Background()
15→
16→	var result int
17→	if err := pool.QueryRow(ctx, "SELECT 1").Scan(&result); err != nil {
18→		t.Fatalf("SELECT 1 failed: %v", err)
19→	}
20→	if result != 1 {
21→		t.Fatalf("expected 1, got %d", result)
22→	}
23→}
24→
25→func TestIntegrationTestDBWithSeed(t *testing.T) {
26→	if testing.Short() {
27→		t.Skip("skipping: requires Docker")
28→	}
29→
30→	pool := TestDBWithSeed(t)
31→	ctx := context.Background()
32→
33→	// Verify row counts per table.
34→	checks := []struct {
35→		table   string
36→		minRows int
37→	}{
38→		{"users", 3},
39→		{"items", 9},       // 9 items per user × 3 users = 27 minimum
40→		{"mcp_clients", 2}, // 2 clients for first user
41→		{"audit_log", 6},   // 6 entries
42→	}
43→
44→	for _, c := range checks {
45→		var count int
46→		err := pool.QueryRow(ctx, "SELECT COUNT(*) FROM "+c.table).Scan(&count)
47→		if err != nil {
48→			t.Fatalf("count %s: %v", c.table, err)
49→		}
50→		if count < c.minRows {
51→			t.Errorf("%s: expected >= %d rows, got %d", c.table, c.minRows, count)
52→		}
53→	}
54→}
