310→// TestUploadHandler_ContentSniffReject verifies the handler rejects uploads
311→// where the Content-Type header claims audio but the actual bytes are not audio.
312→func TestUploadHandler_ContentSniffReject(t *testing.T) {
313→	// Create a multipart request with Content-Type: audio/mpeg but PNG content
314→	var buf bytes.Buffer
315→	w := multipart.NewWriter(&buf)
316→
317→	// CreateFormFile sets Content-Type to application/octet-stream by default,
318→	// so we create the part manually with an audio MIME type.
319→	partHeader := make(map[string][]string)
320→	partHeader["Content-Disposition"] = []string{`form-data; name="file"; filename="malicious.mp3"`}
321→	partHeader["Content-Type"] = []string{"audio/mpeg"}
322→	part, err := w.CreatePart(partHeader)
323→	if err != nil {
324→		t.Fatal(err)
325→	}
326→
327→	// Write PNG magic bytes (not audio)
328→	pngHeader := append([]byte{0x89, 0x50, 0x4E, 0x47, 0x0D, 0x0A, 0x1A, 0x0A}, make([]byte, 100)...)
329→	if _, err := part.Write(pngHeader); err != nil {
330→		t.Fatal(err)
331→	}
332→	_ = w.Close()
333→
334→	// We need a non-nil storage to get past the first check.
335→	// Use an empty storage.Client — the handler should reject before reaching S3.
336→	// storage.Client is a struct, so we pass a zero-value pointer.
337→	handler := uploadHandler(&emptyStorage, 50<<20)
338→
339→	req := httptest.NewRequest(http.MethodPost, "/upload", &buf)
340→	req.Header.Set("Content-Type", w.FormDataContentType())
341→	ctx := auth.WithClaims(req.Context(), &auth.Claims{UserID: uuid.New()})
342→	req = req.WithContext(ctx)
343→
344→	rr := httptest.NewRecorder()
345→	handler.ServeHTTP(rr, req)
346→
347→	if rr.Code != http.StatusBadRequest {
348→		t.Errorf("expected 400 for spoofed audio, got %d: %s", rr.Code, rr.Body.String())
349→	}
350→
351→	body := rr.Body.String()
352→	if !bytes.Contains([]byte(body), []byte("does not match")) {
353→		t.Errorf("expected content mismatch error, got: %s", body)
354→	}
355→}
